SELECT

FROM sys_provider_api_template
WHERE config_type = #{configType}
  AND provider_code = #{providerCode}
  AND operation = #{operation}
  AND is_enabled = '1'
LIMIT 1

SELECT

FROM sys_provider_api_template
WHERE config_type = #{configType}
  AND provider_code = #{providerCode}
ORDER BY operation

SELECT

FROM sys_provider_api_template
WHERE is_enabled = '1'

    AND config_type = #{configType}


    AND provider_code = #{providerCode}

ORDER BY config_type, provider_code, operation
